#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int h[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &h[i]);
        }
        long long ans = 1e18;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                long long temp = 0;
                int x = 1;
                for (int k = i; k <= j; k++) {
                    if (h[k] < x) {
                        temp += x - h[k];
                    } else if (h[k] > x) {
                        temp += h[k] - x;
                    }
                    x++;
                }
                x--;
                for (int k = j; k >= i; k--) {
                    if (h[k] < x) {
                        temp += x - h[k];
                    } else if (h[k] > x) {
                        temp += h[k] - x;
                    }
                    x--;
                }
                ans = (ans < temp) ? ans : temp;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

