import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] h = new int[n];
            for (int i = 0; i < n; i++) {
                h[i] = sc.nextInt();
            }
            long ans = Long.MAX_VALUE;
            for (int i = 0; i < n; i++) {
                for (int j = i; j < n; j++) {
                    long temp = 0;
                    int x = 1;
                    for (int k = i; k <= j; k++) {
                        if (h[k] < x) {
                            temp += x - h[k];
                        } else if (h[k] > x) {
                            temp += h[k] - x;
                        }
                        x++;
                    }
                    x--;
                    for (int k = j; k >= i; k--) {
                        if (h[k] < x) {
                            temp += x - h[k];
                        } else if (h[k] > x) {
                            temp += h[k] - x;
                        }
                        x--;
                    }
                    ans = Math.min(ans, temp);
                }
            }
            System.out.println(ans);
        }
    }
}

